import os
import requests
from getpass import getpass

def configure_rabbitmq(vhost, username, password):
    # Create vhost
    create_vhost(vhost)
    
    # Create user and set permissions
    create_user(username, password, "/", ".*")
    set_permissions(username, vhost, ".*", ".*", ".*")

def create_vhost(vhost):
    url = f"http://localhost:15672/api/vhosts/{vhost}"
    headers = {"content-type": "application/json"}
    
    # Check if vhost already exists
    response = requests.get(url, auth=('guest', 'guest'))
    if not response.status_code == 404:
        print(f"VHost {vhost} already exists")
        return
        
    response = requests.put(url, headers=headers, auth=('guest', 'guest'))
    
    if response.status_code == 201:
        print(f"Created vhost {vhost}")
    else:
        print(f"Failed to create vhost {vhost}. Status code: {response.status_code}")
        
def create_user(username, password, tags=None, acls=None):
    url = f"http://localhost:15672/api/users/{username}"
    headers = {"content-type": "application/json"}
    
    # Check if user already exists
    response = requests.get(url, auth=('guest', 'guest'))
    if not response.status_code == 404:
        print(f"User {username} already exists")
        return
        
    data = {"password": password, "tags": tags, "permissions": acls or ""}
    
    response = requests.put(url, headers=headers, auth=('guest', 'guest'), json=data)
    
    if response.status_code == 201:
        print(f"Created user {username}")
    else:
        print(f"Failed to create user {username}. Status code: {response.status_code}")
        
def set_permissions(user, vhost, configure=None, write=None, read=None):
    url = f"http://localhost:15672/api/permissions/{vhost}/{user}"
    headers = {"content-type": "application/json"}
    
    data = {"configure": configure or "", "write": write or "", "read": read or ""}
    
    response = requests.put(url, headers=headers, auth=('guest', 'guest'), json=data)
        
    if response.status_code == 200:
        print(f"Set permissions for {user}@{vhost}")
    else:
        print(f"Failed to set permissions for {user}@{vhost}. Status code: {response.status_code}")
        
if __name__ == "__main__":
    vhost = os.getenv("VHOST", input("Enter the name of the virtual host: "))
    username = os.getenv("USERNAME", input("Enter the username: "))
    
    # Get password from environment variable first, if not available then prompt for it
    password = getpass(prompt="Enter the password: ") or os.getenv("PASSWORD")
    
    configure_rabbitmq(vhost, username, password)